const allItems = $input.all();
const extractItem = allItems[0]?.json || {};
const billData = extractItem.data || extractItem;

const analysisItem = allItems[1]?.json || {};
const savingsAnalysis = analysisItem.answer || analysisItem.markdown || analysisItem.text || '';

const triggerData = $('New Bill').item.json;
const fileName = triggerData.name || 'unknown';
const fileId   = triggerData.id   || '';

// Document info
const docType        = billData.documentType  || 'Statement';
const statementDate  = billData.statementDate || 'N/A';
const accountHolder  = billData.accountHolder || 'N/A';
const accountEnding  = billData.accountEnding || 'N/A';
const totalAmount    = parseFloat(billData.totalAmount) || 0;

// Flat subscription fields from schema
const subscriptionCount  = parseInt(billData.subscriptionCount) || 0;
const subscriptionNames  = billData.subscriptionNames  || 'None found';
const subscriptionAmounts= billData.subscriptionAmounts|| 'N/A';
const monthlySubTotal    = parseFloat(billData.monthlySubTotal) || 0;
const annualSubTotal     = parseFloat(billData.annualSubTotal)  || monthlySubTotal * 12;
const hasDuplicates      = billData.hasDuplicates || false;
const duplicateNames     = billData.duplicateNames || 'None';
const unusedSubscriptions= billData.unusedSubscriptions || 'None';
const potentialSavings   = parseFloat(billData.potentialSavings) || 0;
const largestSubscription= billData.largestSubscription || 'N/A';
const largestAmount      = parseFloat(billData.largestAmount) || 0;

// Count cancel/downgrade from AI analysis
let cancelCount    = (savingsAnalysis.match(/cancel/gi) || []).length;
let downgradeCount = (savingsAnalysis.match(/downgrade/gi) || []).length;

return [{ json: {
  fileName,
  fileId,
  documentType:              docType,
  statementDate,
  accountHolder,
  accountEnding,
  totalBillAmount:           totalAmount,
  subscriptionCount,
  subscriptionNames,
  subscriptionAmounts,
  totalMonthlySubscriptions: monthlySubTotal.toFixed(2),
  totalAnnualSubscriptions:  annualSubTotal.toFixed(2),
  hasDuplicateServices:      hasDuplicates,
  duplicateNames,
  unusedSubscriptions,
  largestSubscription,
  largestAmount,
  potentialMonthlySavings:   potentialSavings.toFixed(2),
  potentialAnnualSavings:    (potentialSavings * 12).toFixed(2),
  cancelRecommendations:     cancelCount,
  downgradeRecommendations:  downgradeCount,
  savingsAnalysis:           savingsAnalysis.slice(0, 500),
  processedAt:               new Date().toISOString()
}}];

